import type { PropDef } from "./parser.js";

export { type GeneratedComponent, type PropDef, registry };

const STORAGE_KEY = "component-generator:registry";
const STORAGE_VERSION_KEY = "component-generator:registry-version";
const CURRENT_VERSION = 4;

/**
 * A component that has been generated by the model.
 */
interface GeneratedComponent {
  /** Display name, e.g. "Pie Chart" */
  name: string;
  /** Kebab-case tag, e.g. "pie-chart" */
  tag: string;
  /** PascalCase React component name, e.g. "PieChart" */
  componentName: string;
  /** Original user description — used in the prompt so the model knows when to reuse this */
  description: string;
  /** Extracted @prop annotations documenting the component's API surface */
  props: PropDef[];
  /** This component's own source code (just the function, not the full block) */
  code: string;
  /** Shared code from the same generation (constants, style objects, etc.) */
  sharedCode: string;
  /** True if this is the main/parent component, false for sub-components */
  isMain: boolean;
  /** When it was generated */
  timestamp: number;
  /** Groups components from the same generation */
  generationId: string;
}

/**
 * In-memory registry of generated components, backed by localStorage.
 * Components are keyed by their tag name.
 */
const registry = {
  _components: new Map<string, GeneratedComponent>(),

  /** Load from localStorage on startup. */
  load(): void {
    try {
      const version = Number(localStorage.getItem(STORAGE_VERSION_KEY) ?? 0);
      if (version < CURRENT_VERSION) {
        // Old schema — clear stale entries that would cause errors.
        localStorage.removeItem(STORAGE_KEY);
        localStorage.setItem(STORAGE_VERSION_KEY, String(CURRENT_VERSION));
        return;
      }
      const stored = localStorage.getItem(STORAGE_KEY);
      if (!stored) return;
      const entries: GeneratedComponent[] = JSON.parse(stored);
      for (const entry of entries) {
        this._components.set(entry.tag, entry);
      }
    } catch {
      // Corrupted storage — start fresh.
    }
  },

  /** Persist to localStorage. */
  _save(): void {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.all()));
    localStorage.setItem(STORAGE_VERSION_KEY, String(CURRENT_VERSION));
  },

  /** Add or update a component in the registry. */
  add(component: GeneratedComponent): void {
    this._components.set(component.tag, component);
    this._save();
  },

  /** Remove a component by tag. */
  delete(tag: string): boolean {
    const deleted = this._components.delete(tag);
    if (deleted) this._save();
    return deleted;
  },

  /** Get a component by tag. */
  get(tag: string): GeneratedComponent | undefined {
    return this._components.get(tag);
  },

  /** Get all registered components. */
  all(): GeneratedComponent[] {
    return [...this._components.values()];
  },

  /** Get only main (top-level) components. */
  mains(): GeneratedComponent[] {
    return this.all().filter((c) => c.isMain);
  },

  /**
   * Group components by generationId.
   * Returns an array of groups, each with a main component and its children.
   * Groups are ordered by timestamp (newest first).
   */
  groups(): { main: GeneratedComponent; children: GeneratedComponent[] }[] {
    const byGen = new Map<string, GeneratedComponent[]>();
    for (const c of this.all()) {
      const id = c.generationId ?? c.tag;
      if (!byGen.has(id)) byGen.set(id, []);
      byGen.get(id)!.push(c);
    }

    const groups: {
      main: GeneratedComponent;
      children: GeneratedComponent[];
    }[] = [];
    for (const members of byGen.values()) {
      const main = members.find((c) => c.isMain) ?? members[0];
      const children = members.filter((c) => c !== main);
      groups.push({ main, children });
    }

    // Newest first.
    groups.sort((a, b) => b.main.timestamp - a.main.timestamp);
    return groups;
  },

  /** Check if a component exists by tag. */
  has(tag: string): boolean {
    return this._components.has(tag);
  },

  /** Number of registered components. */
  get size(): number {
    return this._components.size;
  },

  /**
   * Build the "available components" section for the system prompt.
   * Lists each component's name and source code so the model can
   * reference them when composing.
   */
  toPromptContext(): string {
    if (this._components.size === 0) return "";

    const entries = this.all().map((c) => {
      const propsSection = c.props ? `\nProps:\n${c.props}` : "";
      return `### ${c.name} (use as <${c.componentName} />)\n**Use when:** ${c.description}${propsSection}\n\`\`\`jsx\n${c.code}\n\`\`\``;
    });

    return [
      "",
      "## Previously Generated Components",
      "You can import and use these components in your code.",
      "They are already available in scope — just use them as JSX elements.",
      "",
      ...entries,
    ].join("\n");
  },
};

// Load persisted components on module init.
registry.load();
